using System.Net.Http.Json;
using sv_2d207a52fefa4cc78651e951444d12c3.Client.Models;

namespace sv_2d207a52fefa4cc78651e951444d12c3.Client.Services;

/// <summary>
/// WASM-side implementation that calls the server API over HTTP.
/// </summary>
public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var shipment = await http.GetFromJsonAsync<Shipment>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return shipment ?? throw new InvalidOperationException("Shipment not found.");
    }
}

