                    Description = "In transit to destination",
                    Location = "Chicago, IL"
                }
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero),
                    Description = "Package picked up",
                    Location = "Seattle, WA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 24, 9, 0, 0, TimeSpan.Zero),
                    Description = "Out for delivery",
                    Location = "San Francisco, CA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 24, 14, 45, 0, TimeSpan.Zero),
