                }
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 27, 1, 0, 0, TimeSpan.Zero),
                    Description = "Label created, awaiting pickup",
                    Location = "Dallas, TX"
