@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_2d207a52fefa4cc78651e951444d12c3.Client.Models
@using sv_2d207a52fefa4cc78651e951444d12c3.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h1>Shipment Tracker</h1>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="card mb-3">
        <div class="card-header">
            <strong>@_shipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <p><strong>Status:</strong> @_shipment.Status</p>
            <p><strong>Location:</strong> @_shipment.Location</p>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <p><strong>Estimated Delivery:</strong> @_shipment.EstimatedDelivery.Value.ToString("f")</p>
            }
        </div>
    </div>

    @if (_shipment.Updates.Count > 0)
    {
        <h2>Status Updates</h2>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Description</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.Updates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                        <td>@update.Location</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;
    private string _lastLoadedTrackingNumber = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(TrackingNumber, _lastLoadedTrackingNumber, StringComparison.OrdinalIgnoreCase)
            && (_shipment is not null || _errorMessage is not null))
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        await CancelPendingRequestAsync();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was canceled (navigation away or parameter change) — nothing to show.
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogWarning("Shipment request for {TrackingNumber} timed out.", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (HttpRequestException ex)
        {
            Logger.LogError(ex, "Network error fetching shipment {TrackingNumber}.", TrackingNumber);
            _errorMessage = "A network error occurred. Please check your connection and try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogWarning(ex, "Timeout fetching shipment {TrackingNumber}.", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException)
        {
            _errorMessage = $"No shipment found for tracking number \"{TrackingNumber}\".";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Unexpected error fetching shipment {TrackingNumber}.", TrackingNumber);
            _errorMessage = "Something went wrong. Please try again later.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    private async ValueTask CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

