                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 27, 6, 15, 0, TimeSpan.Zero),
                    Description = "In transit to destination",
                    Location = "Chicago, IL"
                }
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 12, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero),
                    Description = "Package picked up",
                    Location = "Seattle, WA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 24, 9, 0, 0, TimeSpan.Zero),
                    Description = "Out for delivery",
                    Location = "San Francisco, CA"
                },
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 24, 14, 45, 0, TimeSpan.Zero),
                    Description = "Delivered — signed by J. Smith",
                    Location = "San Francisco, CA"
                }
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            Updates =
            [
                new StatusUpdate
                {
                    Timestamp = new DateTimeOffset(2026, 5, 27, 1, 0, 0, TimeSpan.Zero),
                    Description = "Label created, awaiting pickup",
                    Location = "Dallas, TX"
                }
            ]
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

