 using sv_2d207a52fefa4cc78651e951444d12c3.Client.Pages;
 using sv_2d207a52fefa4cc78651e951444d12c3.Client.Services;
 using sv_2d207a52fefa4cc78651e951444d12c3.Components;
 using sv_2d207a52fefa4cc78651e951444d12c3.Services;

 var builder = WebApplication.CreateBuilder(args);

 // Add services to the container.
 builder.Services.AddRazorComponents()
     .AddInteractiveServerComponents()
     .AddInteractiveWebAssemblyComponents();

 builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

 var app = builder.Build();

 // Configure the HTTP request pipeline.
 if (app.Environment.IsDevelopment())
 {
     app.UseWebAssemblyDebugging();
 }
 else
 {
     app.UseExceptionHandler("/Error", createScopeForErrors: true);
 }
 app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
 app.UseAntiforgery();

 app.MapStaticAssets();
 app.MapRazorComponents<App>()
     .AddInteractiveServerRenderMode()
     .AddInteractiveWebAssemblyRenderMode()
     .AddAdditionalAssemblies(typeof(sv_2d207a52fefa4cc78651e951444d12c3.Client._Imports).Assembly);

 app.MapGet("api/shipments/{trackingNumber}", async (
     string trackingNumber,
     IShipmentService service,
     CancellationToken ct) =>
 {
     try
     {
         var shipment = await service.GetShipmentAsync(trackingNumber, ct);
         return Results.Ok(shipment);
     }
     catch (KeyNotFoundException)
     {
         return Results.NotFound();
     }
 });

 app.Run();
